import { Component, effect, OnInit, signal } from '@angular/core';
import { CardsService } from '../../services/cards.service';
import { Card } from '../cards.model';
import { CommonModule } from '@angular/common';

@Component({
    selector: 'app-user-cards',
    standalone: true,
    templateUrl: './user-cards.component.html',
    styleUrls: ['./user-cards.component.css'],
    imports: [CommonModule],
})
export class UserCardsComponent implements OnInit {

    isFetching = signal(false);
    availableCardsFetching = signal(false);
    error = signal('');
    fallbackMessage = signal('');  // Convert to signal


    userCards = this.cardsService.loadedUserCards;

    constructor(public cardsService: CardsService) {
        effect(() => {
            this.updateFallbackMessage();
        });
    }

    ngOnInit() {
        this.isFetching.set(true);
        try {
            this.cardsService.loadUserCards();
        } catch (err: any) {
            this.error.set(err.message || 'Failed to load user cards.');
            console.error('Error loading user cards:', err);
        } finally {
            this.isFetching.set(false);
        }
    }
    onRemoveCard(card: Card) {
        try {
            this.cardsService.removeUserCard(card);
            this.updateFallbackMessage(); // Update message after removal
            console.log(`Card "${card.title}" removed successfully.`);
        } catch (err: any) {
            console.error('Error removing card:', err);
            this.error.set('Failed to remove the card.');
        }
    }

    trackById(index: number, card: Card): string {
        return card.id;
    }

    private updateFallbackMessage(): void {
        if (this.isFetching() || this.availableCardsFetching()) {
            this.fallbackMessage.set('Loading the Forbidden Pieces...');
        } else if (this.userCards.length > 0) { 
            this.fallbackMessage.set('Exodia refuses this order! Try again...');
        } else if (this.userCards().length > 0) {
            this.fallbackMessage.set('Complete the Forbidden Assembly');
        } else {
            this.fallbackMessage.set('');
        }
    }

}
